def checkAdminPassword(password):
    import re
    if len(password) < 12:
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'[0-9]', password):
        return False
    if not re.search(r'[!@#$%^&*()-_=+[]{}|;:,.<>?]', password):
        return False
    if re.search(r'\s', password):
        return False
    common = {'password', '123456', 'admin', '123456789', 'qwerty', 'letmein', 'dragon', '12345678', 'sunshine', 'iloveyou'}
    return password not in common

